1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const DEDUCTIBLE = 100;
30	const CAP_MULTIPLIER = 2;
31	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
32	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
33	
34	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
35	type QuoteStep = { op: "quote"; items: Item[] };
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Customer = { yearsWithMHPCO: number };
41	type Scenario = { customer: Customer; steps: Step[] };
42	
43	const sum = (numbers: number[]): number =>
44	  numbers.reduce((total, n) => total + n, 0);
45	
46	// Gold pieces are whole units. Premiums round up (customer pays slightly more);
47	// payouts round down (insurer pays slightly less) — the asymmetry favors the office.
48	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
49	const roundDownToWholeGold = (amount: number): number => Math.floor(amount);
50	
51	const policyInsuranceSum = (items: Item[]): number =>
52	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
53	
54	const isHighEnchantmentForReimbursement = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
56	
57	const effectiveDamage = (item: Item, damageAmount: number): number =>
58	  isHighEnchantmentForReimbursement(item)
59	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
60	    : damageAmount;
61	
62	const findPolicyItem = (policyItems: Item[], itemType: string): Item => {
63	  const found = policyItems.find((item) => item.type === itemType);
64	  if (!found) throw new Error(`damage references item type '${itemType}' not in policy`);
65	  return found;
66	};
67	
68	const damagePayout = (policyItems: Item[], damage: Damage): number =>
69	  effectiveDamage(findPolicyItem(policyItems, damage.itemType), damage.amount) - DEDUCTIBLE;
70	
71	type Policy = { items: Item[]; remainingCap: number };
72	
73	const newPolicy = (items: Item[]): Policy => ({
74	  items,
75	  remainingCap: CAP_MULTIPLIER * policyInsuranceSum(items),
76	});
77	
78	const validateClaim = (damages: Damage[]): void => {
79	  const negative = damages.find((damage) => damage.amount < 0);
80	  if (negative) throw new Error(`damage amount must be non-negative: ${negative.amount}`);
81	};
82	
83	const claimResult = (policy: Policy, step: ClaimStep) => {
84	  validateClaim(step.incident.damages);
85	  const computedPayout = sum(step.incident.damages.map((damage) => damagePayout(policy.items, damage)));
86	  const payout = roundDownToWholeGold(Math.min(computedPayout, policy.remainingCap));
87	  return { payout, remainingCap: policy.remainingCap - payout };
88	};
89	
90	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
91	
92	const isBlockOfThreeAlike = (items: Item[]): boolean =>
93	  items.length === 3 && items.every((item) => item.type === items[0].type);
94	
95	const groupByType = (items: Item[]): Item[][] => {
96	  const groups: Record<string, Item[]> = {};
97	  for (const item of items) {
98	    (groups[item.type] ||= []).push(item);
99	  }
100	  return Object.values(groups);
101	};
102	
103	const groupBasePremium = (group: Item[]): number =>
104	  isBlockOfThreeAlike(group)
105	    ? BLOCK_OF_THREE_BASE_PREMIUM
106	    : sum(group.map(itemBasePremium));
107	
108	const itemsBasePremium = (items: Item[]): number =>
109	  sum(groupByType(items).map(groupBasePremium));
110	
111	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
112	  applies ? amount * rate : 0;
113	
114	const cursedSurcharge = (item: Item): number =>
115	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
116	
117	const highEnchantmentSurcharge = (item: Item): number =>
118	  rateIfApplies(
119	    itemBasePremium(item),
120	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
121	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
122	  );
123	
124	const itemSurchargesTotal = (items: Item[]): number =>
125	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
126	
127	const firstInsuranceSurcharge = (basePremium: number): number =>
128	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
129	
130	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
131	  rateIfApplies(
132	    basePremium,
133	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
134	    LOYALTY_DISCOUNT_RATE,
135	  );
136	
137	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
138	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
139	
140	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
141	  const policyBase = itemsBasePremium(items);
142	  return roundUpToWholeGold(
143	    policyBase +
144	      itemSurchargesTotal(items) +
145	      firstInsuranceSurcharge(policyBase) -
146	      loyaltyDiscount(policyBase, customer) -
147	      followupDiscount(policyBase, quoteIndex) +
148	      PROCESSING_FEE,
149	  );
150	};
151	
152	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUMS));
153	
154	const validateItemTypes = (items: Item[]): void => {
155	  const unknown = items.find((item) => !KNOWN_ITEM_TYPES.has(item.type));
156	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
157	};
158	
159	export const runScenario = (input: Scenario): unknown => {
160	  const results: unknown[] = [];
161	  const policies: Policy[] = [];
162	  for (const step of input.steps) {
163	    if (step.op === "quote") {
164	      validateItemTypes(step.items);
165	      const premium = quotePremiumFor(step.items, input.customer, policies.length);
166	      results.push({ premium });
167	      policies.push(newPolicy(step.items));
168	    } else {
169	      const result = claimResult(policies[step.policy], step);
170	      policies[step.policy].remainingCap = result.remainingCap;
171	      results.push(result);
172	    }
173	  }
174	  return { results };
175	};
